-- Goal Setting scenario — Check Goals and Update Goals paths
-- Stable keys map to src/data/goalSettingCheckGoalsPathFallback.ts and goalSettingUpdateGoalsPathFallback.ts

-- Check Goals
values ('a0000000-0000-4000-8000-000000000814', 'a0000000-0000-4000-8000-000000000204', 'Check Goals', 'Goals already set, but deadline not reached.', 'alternative')
on conflict (id) do update set service_scenario_id = excluded.service_scenario_id, name = excluded.name, description = excluded.description, path_type = excluded.path_type;
delete from public.cell_triggers where source_cell_id in (select id from public.cells where path_id = 'a0000000-0000-4000-8000-000000000814');
delete from public.cells where path_id = 'a0000000-0000-4000-8000-000000000814';
delete from public.layers where path_id = 'a0000000-0000-4000-8000-000000000814';
delete from public.path_steps where path_id = 'a0000000-0000-4000-8000-000000000814';
on conflict (id) do update set name = excluded.name, row_position = excluded.row_position, path_id = excluded.path_id;
on conflict (id) do update set name = excluded.name, service_scenario_id = excluded.service_scenario_id;
on conflict (path_id, step_id) do update set column_position = excluded.column_position;
on conflict (id) do update set path_id = excluded.path_id, layer_id = excluded.layer_id, step_id = excluded.step_id, content = excluded.content;
on conflict (id) do update set source_cell_id = excluded.source_cell_id, target_cell_id = excluded.target_cell_id;

